109→void do_physics_align_object( object * obj )
110→{
111→#ifdef USE_OX_BRIDGE
112→	static int ox_bridge_logged = 0;
113→	if (!ox_bridge_logged)
114→	{
115→		fprintf(stderr, "[OX] do_physics_align_object (D2) using cd_ox_do_physics_align_object.\n");
116→		ox_bridge_logged = 1;
117→	}
118→	int32_t packed[54];
119→	segment* seg = &Segments[obj->segnum];
120→	for (int i = 0; i < 6; i++) {
121→		#ifdef COMPACT_SEGS
122→			vms_vector _n0;
123→			get_side_normal(seg, i, 0, &_n0);
124→			packed[i*3]     = _n0.x;
125→			packed[i*3 + 1] = _n0.y;
126→			packed[i*3 + 2] = _n0.z;
127→		#else
128→			packed[i*3]     = seg->sides[i].normals[0].x;
129→			packed[i*3 + 1] = seg->sides[i].normals[0].y;
130→			packed[i*3 + 2] = seg->sides[i].normals[0].z;
131→		#endif
132→	}
133→	for (int i = 0; i < 6; i++) {
134→		#ifdef COMPACT_SEGS
135→			vms_vector _n1;
136→			get_side_normal(seg, i, 1, &_n1);
137→			packed[18 + i*3]     = _n1.x;
138→			packed[18 + i*3 + 1] = _n1.y;
139→			packed[18 + i*3 + 2] = _n1.z;
140→		#else
141→			packed[18 + i*3]     = seg->sides[i].normals[1].x;
142→			packed[18 + i*3 + 1] = seg->sides[i].normals[1].y;
143→			packed[18 + i*3 + 2] = seg->sides[i].normals[1].z;
144→		#endif
145→	}
146→	for (int i = 0; i < 6; i++)
147→		packed[36 + i] = get_num_faces(&seg->sides[i]);
148→	packed[42] = obj->orient.rvec.x; packed[43] = obj->orient.rvec.y; packed[44] = obj->orient.rvec.z;
149→	packed[45] = obj->orient.uvec.x; packed[46] = obj->orient.uvec.y; packed[47] = obj->orient.uvec.z;
150→	packed[48] = obj->orient.fvec.x; packed[49] = obj->orient.fvec.y; packed[50] = obj->orient.fvec.z;
151→	packed[51] = obj->mtype.phys_info.turnroll;
152→	packed[52] = floor_levelling ? 1 : 0;
153→	packed[53] = FrameTime;
154→	int32_t out_buf[11];
155→	cd_ox_do_physics_align_object(packed, 54, out_buf);
156→	if (out_buf[0]) {
157→		obj->orient.rvec.x = out_buf[1]; obj->orient.rvec.y = out_buf[2]; obj->orient.rvec.z = out_buf[3];
158→		obj->orient.uvec.x = out_buf[4]; obj->orient.uvec.y = out_buf[5]; obj->orient.uvec.z = out_buf[6];
159→		obj->orient.fvec.x = out_buf[7]; obj->orient.fvec.y = out_buf[8]; obj->orient.fvec.z = out_buf[9];
160→	}
161→	floor_levelling = out_buf[10];
162→#else
163→	vms_vector desired_upvec;
164→	fixang delta_ang,roll_ang;
165→	//vms_vector forvec = {0,0,f1_0};
166→	vms_matrix temp_matrix;
167→	fix d,largest_d=-f1_0;
168→	int i,best_side;
169→
170→
171→	// bank player according to segment orientation
172→
173→	//find side of segment that player is most alligned with
174→
175→	for (i=0;i<6;i++) {
176→		#ifdef COMPACT_SEGS
177→			vms_vector _tv1;
178→			get_side_normal( &Segments[obj->segnum], i, 0, &_tv1 );
179→			d = vm_vec_dot(&_tv1,&obj->orient.uvec);
180→		#else
181→			d = vm_vec_dot(&Segments[obj->segnum].sides[i].normals[0],&obj->orient.uvec);
182→		#endif
183→
184→		if (d > largest_d) {largest_d = d; best_side=i;}
185→	}
186→
187→	if (floor_levelling) {
188→
189→		// old way: used floor's normal as upvec
190→		#ifdef COMPACT_SEGS
191→			get_side_normal(&Segments[obj->segnum], 3, 0, &desired_upvec );
192→		#else
193→			desired_upvec = Segments[obj->segnum].sides[3].normals[0];
194→		#endif
195→
196→	}
197→	else  // new player leveling code: use normal of side closest to our up vec
198→		if (get_num_faces(&Segments[obj->segnum].sides[best_side])==2) {
199→			#ifdef COMPACT_SEGS
200→				vms_vector normals[2];
201→				get_side_normals(&Segments[obj->segnum], best_side, &normals[0], &normals[1] );
202→
203→				desired_upvec.x = (normals[0].x + normals[1].x) / 2;
204→				desired_upvec.y = (normals[0].y + normals[1].y) / 2;
205→				desired_upvec.z = (normals[0].z + normals[1].z) / 2;
206→
207→				vm_vec_normalize(&desired_upvec);
208→			#else
209→				side *s = &Segments[obj->segnum].sides[best_side];
210→				desired_upvec.x = (s->normals[0].x + s->normals[1].x) / 2;
211→				desired_upvec.y = (s->normals[0].y + s->normals[1].y) / 2;
212→				desired_upvec.z = (s->normals[0].z + s->normals[1].z) / 2;
213→
214→				vm_vec_normalize(&desired_upvec);
215→			#endif
216→		}
217→		else
218→			#ifdef COMPACT_SEGS
219→				get_side_normal(&Segments[obj->segnum], best_side, 0, &desired_upvec );
220→			#else
221→				desired_upvec = Segments[obj->segnum].sides[best_side].normals[0];
222→			#endif
223→
224→	if (labs(vm_vec_dot(&desired_upvec,&obj->orient.fvec)) < f1_0/2) {
225→		fixang save_delta_ang;
226→		vms_angvec tangles;
227→
228→		vm_vector_2_matrix(&temp_matrix,&obj->orient.fvec,&desired_upvec,NULL);
229→
230→		save_delta_ang = delta_ang = vm_vec_delta_ang(&obj->orient.uvec,&temp_matrix.uvec,&obj->orient.fvec);
231→
232→		delta_ang += obj->mtype.phys_info.turnroll;
233→
234→		if (abs(delta_ang) > DAMP_ANG) {
235→			vms_matrix rotmat, new_pm;
236→
237→			roll_ang = fixmul(FrameTime,ROLL_RATE);
238→
239→			if (abs(delta_ang) < roll_ang) roll_ang = delta_ang;
240→			else if (delta_ang<0) roll_ang = -roll_ang;
241→
242→			tangles.p = tangles.h = 0;  tangles.b = roll_ang;
243→			vm_angles_2_matrix(&rotmat,&tangles);
244→
245→			vm_matrix_x_matrix(&new_pm,&obj->orient,&rotmat);
246→			obj->orient = new_pm;
247→		}
248→		else floor_levelling=0;
249→	}
250→#endif
251→
252→}
