254→void set_object_turnroll(object *obj)
255→{
256→#ifdef USE_OX_BRIDGE
257→	obj->mtype.phys_info.turnroll = cd_ox_set_object_turnroll(
258→		obj->mtype.phys_info.rotvel.y,
259→		obj->mtype.phys_info.turnroll,
260→		FrameTime);
261→#else
262→	fixang desired_bank;
263→
264→	desired_bank = -fixmul(obj->mtype.phys_info.rotvel.y,TURNROLL_SCALE);
265→
266→	if (obj->mtype.phys_info.turnroll != desired_bank) {
267→		fixang delta_ang,max_roll;
268→
269→		max_roll = fixmul(ROLL_RATE,FrameTime);
270→
271→		delta_ang = desired_bank - obj->mtype.phys_info.turnroll;
272→
273→		if (labs(delta_ang) < max_roll)
274→			max_roll = delta_ang;
275→		else
276→			if (delta_ang < 0)
277→				max_roll = -max_roll;
278→
279→		obj->mtype.phys_info.turnroll += max_roll;
280→	}
281→#endif
282→}
