443→void do_physics_sim(object *obj)
444→{
445→#ifdef USE_OX_BRIDGE
446→	Assert(obj->type != OBJ_NONE);
447→	Assert(obj->movement_type == MT_PHYSICS);
448→
449→#ifndef NDEBUG
450→	if (Dont_move_ai_objects)
451→		if (obj->control_type == CT_AI)
452→			return;
453→#endif
454→
455→	// Set C-side globals needed by FVI
456→	disable_new_fvi_stuff = (obj->type != OBJ_PLAYER);
457→
458→	// One-time registration of effect callbacks
459→	static object* ps_obj = nullptr;
460→	{
461→		static int reg = 0;
462→		if (!reg) {
463→			reg = 1;
464→			cd_ox_register_physics_sim_effects(
465→				// find_vector_intersection
466→				[](const int32_t* query, int query_len, int32_t* result, int* result_len) {
467→					fvi_query fq;
468→					fvi_info hi;
469→					vms_vector p0 = {query[0], query[1], query[2]};
470→					vms_vector p1 = {query[3], query[4], query[5]};
471→					fq.p0 = &p0;
472→					fq.p1 = &p1;
473→					fq.rad = query[6];
474→					fq.thisobjnum = query[7];
475→					fq.flags = query[8];
476→					fq.startseg = query[9];
477→					int n_ignore = query[10];
478→					int ignore_list[MAX_IGNORE_OBJS];
479→					for (int i = 0; i < n_ignore && i < MAX_IGNORE_OBJS; i++)
480→						ignore_list[i] = query[11 + i];
481→					if (n_ignore > 0) {
482→						ignore_list[n_ignore] = -1;
483→						fq.ignore_obj_list = ignore_list;
484→					} else {
485→						fq.ignore_obj_list = nullptr;
486→					}
487→					int fate = find_vector_intersection(&fq, &hi);
488→					result[0] = fate;
489→					result[1] = hi.hit_pnt.x;
490→					result[2] = hi.hit_pnt.y;
491→					result[3] = hi.hit_pnt.z;
492→					result[4] = hi.hit_seg;
493→					result[5] = hi.hit_side;
494→					result[6] = hi.hit_side_seg;
495→					result[7] = hi.hit_object;
496→					result[8] = hi.hit_wallnorm.x;
497→					result[9] = hi.hit_wallnorm.y;
498→					result[10] = hi.hit_wallnorm.z;
499→					result[11] = hi.n_segs;
500→					for (int i = 0; i < hi.n_segs && i < MAX_FVI_SEGS; i++)
501→						result[12 + i] = hi.seglist[i];
502→					*result_len = 12 + hi.n_segs;
503→				},
504→				// collide_object_with_wall
505→				[](int hit_speed, int wall_seg, int wall_side,
506→				   int hit_px, int hit_py, int hit_pz, int obj_flags) -> int {
507→					vms_vector hp = {hit_px, hit_py, hit_pz};
508→					ps_obj->flags = obj_flags;
509→					// OCaml updates cur_pos before this effect, but ps_obj->pos is stale.
510→					// C-only path does obj->pos = ipos before collision handlers.
511→					// Sync ps_obj->pos so collision handlers (e.g. fireball creation) use correct position.
512→					ps_obj->pos = hp;
513→					collide_object_with_wall(ps_obj, (fix)hit_speed, wall_seg, wall_side, &hp);
514→					return ps_obj->flags;
515→				},
516→				// scrape_object_on_wall
517→				[](int wall_seg, int wall_side,
518→				   int hit_px, int hit_py, int hit_pz) -> int {
519→					vms_vector hp = {hit_px, hit_py, hit_pz};
520→					ps_obj->pos = hp;
521→					scrape_object_on_wall(ps_obj, wall_seg, wall_side, &hp);
522→					return ps_obj->flags;
523→				},
524→				// collide_two_objects
525→				[](int hit_objnum, int pos_hit_x, int pos_hit_y, int pos_hit_z,
526→				   int32_t* obj_flags_out, int32_t* new_vx, int32_t* new_vy, int32_t* new_vz) {
527→					vms_vector pos_hit = {pos_hit_x, pos_hit_y, pos_hit_z};
528→					collide_two_objects(ps_obj, &Objects[hit_objnum], &pos_hit);
529→					*obj_flags_out = ps_obj->flags;
530→					*new_vx = ps_obj->mtype.phys_info.velocity.x;
531→					*new_vy = ps_obj->mtype.phys_info.velocity.y;
532→					*new_vz = ps_obj->mtype.phys_info.velocity.z;
533→				},
