535→				[](int objnum, int new_seg) {
536→					obj_relink(objnum, new_seg);
537→				},
538→				// find_object_seg
539→				[](int objnum) -> int {
540→					return find_object_seg(&Objects[objnum]);
541→				},
542→				// update_object_seg
543→				[](int objnum) {
544→					update_object_seg(&Objects[objnum]);
545→				},
546→				// find_point_seg
547→				[](int px, int py, int pz, int seg) -> int {
548→					vms_vector p = {px, py, pz};
549→					return find_point_seg(&p, seg);
