566→				// find_connect_side
567→				[](int seg1, int seg2) -> int {
568→					return find_connect_side(&Segments[seg1], &Segments[seg2]);
569→				},
570→				// wall_is_doorway
571→				[](int seg, int side) -> int {
572→					return WALL_IS_DOORWAY(&Segments[seg], side);
573→				},
574→				// create_abs_vertex_lists_and_dist
575→				[](int seg, int side, int spx, int spy, int spz,
576→				   int32_t* dist, int32_t* nx, int32_t* ny, int32_t* nz) {
577→					int num_faces, vertex_list[6];
578→					create_abs_vertex_lists(&num_faces, vertex_list, seg, side);
579→					int vertnum = vertex_list[0];
580→					for (int i = 1; i < 4; i++)
581→						if (vertex_list[i] < vertnum)
582→							vertnum = vertex_list[i];
583→					vms_vector start_pos = {spx, spy, spz};
584→					struct side* s = &Segments[seg].sides[side];
585→					#ifdef COMPACT_SEGS
586→					vms_vector _vn;
587→					get_side_normal(&Segments[seg], side, 0, &_vn);
588→					*dist = vm_dist_to_plane(&start_pos, &_vn, &Vertices[vertnum]);
589→					*nx = _vn.x; *ny = _vn.y; *nz = _vn.z;
590→					#else
591→					*dist = vm_dist_to_plane(&start_pos, &s->normals[0], &Vertices[vertnum]);
592→					*nx = s->normals[0].x; *ny = s->normals[0].y; *nz = s->normals[0].z;
593→					#endif
594→				},
595→				// tmap_is_force_field
596→				[](int seg, int side) -> int {
597→					return (TmapInfo[Segments[seg].sides[side].tmap_num].flags & TMI_FORCE_FIELD) ? 1 : 0;
598→				},
599→				// vm_vector_2_matrix_orient
600→				[](int vx, int vy, int vz, int ux, int uy, int uz, int32_t* out) {
601→					vms_vector fwd = {vx, vy, vz};
602→					vms_vector up = {ux, uy, uz};
603→					vms_matrix m;
604→					vm_vector_2_matrix(&m, &fwd, &up, nullptr);
605→					out[0] = m.rvec.x; out[1] = m.rvec.y; out[2] = m.rvec.z;
606→					out[3] = m.uvec.x; out[4] = m.uvec.y; out[5] = m.uvec.z;
607→					out[6] = m.fvec.x; out[7] = m.fvec.y; out[8] = m.fvec.z;
608→				}
609→			);
610→			cd_ox_register_collision_effects(
611→				// fetch_collision_data
612→				[](int hit_objnum, int32_t* out, int out_len) {
613→					(void)out_len;
