168→//given the specified force, apply damage from that force to an object
169→void apply_force_damage(object* obj, fix force, object* other_obj)
170→{
171→	int	result;
172→	fix damage;
173→
174→	if (obj->flags & (OF_EXPLODING | OF_SHOULD_BE_DEAD))
175→		return;		//already exploding or dead
176→
177→	damage = fixdiv(force, obj->mtype.phys_info.mass) / 8;
178→
179→	if ((other_obj->type == OBJ_PLAYER) && Monster_mode)
180→		damage = 0x7fffffff;
181→
182→	//mprintf((0,"obj %d, damage=%x\n",obj-Objects,damage));
183→
184→	switch (obj->type) {
185→
186→	case OBJ_ROBOT:
187→
188→		if (Robot_info[obj->id].attack_type == 1) {
189→			if (other_obj->type == OBJ_WEAPON)
190→				result = apply_damage_to_robot(obj, damage / 4, other_obj->ctype.laser_info.parent_num);
191→			else
192→				result = apply_damage_to_robot(obj, damage / 4, other_obj - Objects);
193→		}
194→		else {
195→			if (other_obj->type == OBJ_WEAPON)
196→				result = apply_damage_to_robot(obj, damage / 2, other_obj->ctype.laser_info.parent_num);
197→			else
198→				result = apply_damage_to_robot(obj, damage / 2, other_obj - Objects);
199→		}
200→
201→		if (result && (other_obj->ctype.laser_info.parent_signature == ConsoleObject->signature))
202→			add_points_to_score(Robot_info[obj->id].score_value);
203→		break;
204→
205→	case OBJ_PLAYER:
206→
207→		//	If colliding with a claw type robot, do damage proportional to FrameTime because you can collide with those
208→		//	bots every frame since they don't move.
209→		if ((other_obj->type == OBJ_ROBOT) && (Robot_info[other_obj->id].attack_type))
210→			damage = fixmul(damage, FrameTime * 2);
211→
212→		//	Make trainee easier.
213→		if (Difficulty_level == 0)
214→			damage /= 2;
215→
216→		apply_damage_to_player(obj, other_obj, damage);
217→		break;
218→
219→	case OBJ_CLUTTER:
220→
221→		apply_damage_to_clutter(obj, damage);
222→		break;
223→
224→	case OBJ_CNTRLCEN:
225→
226→		apply_damage_to_controlcen(obj, damage, other_obj - Objects);
227→		break;
228→
229→	case OBJ_WEAPON:
230→
231→		break;		//weapons don't take damage
232→
233→	default:
234→
235→		Int3();
236→
237→	}
238→}
