283→	if (obj0->movement_type != MT_PHYSICS)
284→		t = obj1;
285→	else if (obj1->movement_type != MT_PHYSICS)
286→		t = obj0;
287→
288→	if (t) {
289→		Assert(t->movement_type == MT_PHYSICS);
290→		vm_vec_copy_scale(&force, &t->mtype.phys_info.velocity, -t->mtype.phys_info.mass);
291→		phys_apply_force(t, &force);
292→		return;
293→	}
294→
295→	vm_vec_sub(&force, &obj0->mtype.phys_info.velocity, &obj1->mtype.phys_info.velocity);
296→	vm_vec_scale2(&force, 2 * fixmul(obj0->mtype.phys_info.mass, obj1->mtype.phys_info.mass), (obj0->mtype.phys_info.mass + obj1->mtype.phys_info.mass));
297→
298→	bump_this_object(obj1, obj0, &force, damage_flag);
299→	vm_vec_negate(&force);
300→	bump_this_object(obj0, obj1, &force, damage_flag);
301→
302→}
