1656→	cd_ox_move_away_from_player(
1657→		pptr->velocity.x, pptr->velocity.y, pptr->velocity.z,
1658→		vec_to_player->x, vec_to_player->y, vec_to_player->z,
1659→		objp->orient.uvec.x, objp->orient.uvec.y, objp->orient.uvec.z,
1660→		objp->orient.rvec.x, objp->orient.rvec.y, objp->orient.rvec.z,
