1686→			default:	Int3();	//	Impossible, bogus value on objref, must be in 0..3
1687→		}
1688→	}
1689→
1690→
1691→	speed = vm_vec_mag_quick(&pptr->velocity);
1692→
1693→	if (speed > robptr->max_speed[Difficulty_level]) {
1694→		pptr->velocity.x = (pptr->velocity.x*3)/4;
