			packed[base + 5] = (Walls[wn].clip_num >= 0) ? WallAnims[Walls[wn].clip_num].flags : 0;
		} else {
			packed[base + 1] = 0;
			packed[base + 2] = 0;
			packed[base + 3] = 0;
			packed[base + 4] = 0;
