300→//point on plane, whether or not line intersects side
301→//facenum determines which of four possible faces we have
302→//note: the seg parm is temporary, until the face itself has a point field
303→int check_line_to_face(vms_vector *newp,vms_vector *p0,vms_vector *p1,segment *seg,int side,int facenum,int nv,fix rad)
304→{
305→	if ((seg-Segments)==-1)
306→		Error("segnum == -1 in check_line_to_face()");
307→
308→	{
309→	vms_vector checkp;
310→	int pli;
311→	struct side *s=&seg->sides[side];
312→	int vertex_list[6];
313→	int num_faces;
314→	int vertnum;
315→	vms_vector norm;
316→
317→	#ifdef COMPACT_SEGS
318→		get_side_normal(seg, side, facenum, &norm );
319→	#else
320→		norm = seg->sides[side].normals[facenum];
321→	#endif
322→
323→	create_abs_vertex_lists(&num_faces,vertex_list,seg-Segments,side);
324→
325→	//use lowest point number
326→	if (num_faces==2)
327→	{
328→		vertnum = std::min(vertex_list[0],vertex_list[2]);
329→	}
330→	else
331→	{
332→		int i;
333→		vertnum = vertex_list[0];
334→		for (i=1;i<4;i++)
335→			if (vertex_list[i] < vertnum)
336→				vertnum = vertex_list[i];
337→	}
338→
339→	pli = find_plane_line_intersection(newp,&Vertices[vertnum],&norm,p0,p1,rad);
340→
341→	if (!pli) return IT_NONE;
342→
343→	checkp = *newp;
344→
345→	//if rad != 0, project the point down onto the plane of the polygon
346→
347→	if (rad!=0)
348→		vm_vec_scale_add2(&checkp,&norm,-rad);
349→
350→	return check_sphere_to_face(&checkp,s,facenum,nv,rad,vertex_list);
351→	}
352→}
