365→//computes the parameters of closest approach of two lines 
366→//fill in two parameters, t0 & t1.  returns 0 if lines are parallel, else 1
367→int check_line_to_line(fix *t1,fix *t2,vms_vector *p1,vms_vector *v1,vms_vector *p2,vms_vector *v2)
368→{
369→	vms_matrix det;
370→	fix d,cross_mag2;		//mag squared cross product
371→
372→	vm_vec_sub(&det.rvec,p2,p1);
373→	vm_vec_cross(&det.fvec,v1,v2);
