int get_num_faces(side *sidep)
{
	switch (sidep->type) {
		case SIDE_IS_QUAD:	
			return 1;	
			break;
		case SIDE_IS_TRI_02:
		case SIDE_IS_TRI_13:	
			return 2;	
			break;
		default:
			Error("Illegal type = %i\n", sidep->type);
			break;
	}
	return 0; //shut up warning
